            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return True
        return False

    primes = [i for i in range(2, 200) if is_prime(i)]

    # Check all combinations of two primes
    for i in range(len(primes)):
        for j in range(i, len(primes)):
            if primes[i] * primes[j] == a:
                return True
    return False
